// lib/my_package.dart
library my_package;

export 'client/my_client.dart';
// НЕ экспортируем server/

// lib/server.dart
library my_package.server;

export 'server/my_server.dart';
export 'server/storage/my_storage.dart';
export 'client/my_client.dart'; // Сервер может использовать свой клиент

// graph_service/main.dart
import 'package:aq_security/aq_security.dart'; // Клиентский режим

void main() async {
  // Подключается к удалённому серверу безопасности
  await AQSecurity.connect('http://auth-service:8080');

  // Использует через интерфейс
  final canAccess = await IAQAuthService.instance
    .canAccess(userId, resource, 'read');
}

// auth_service/main.dart
import 'package:aq_security/server.dart'; // Серверный режим
import 'package:dart_vault/dart_vault.dart'; // Клиент

void main() async {
  // Vault как удалённый клиент
  await Vault.connect('http://vault-service:8765');

  // Security как сервер (вся логика здесь)
  final authServer = AuthService(
    storage: Vault.instance, // использует vault через клиент
  );

  // Запускает HTTP сервер
  await authServer.serve(port: 8080);
}

// server_apps/auth_service/main.dart

import 'package:aq_security/server.dart';      // ✅ Сервер
import 'package:dart_vault/dart_vault.dart';   // ✅ Клиент

void main() async {
  // 1. Инициализация клиентов
  await Vault.connect('http://vault-service:8765');

  // 2. Создание сервера
  final authServer = AuthService(
    storage: Vault.instance,
    jwtSecret: env['JWT_SECRET'],
  );

  // 3. Регистрация в AQPlatform
  AQPlatform.init(auth: authServer);

  // 4. Запуск HTTP сервера
  await authServer.serve(port: 8080);
  print('Auth service running on :8080');
}

// server_apps/graph_service/main.dart

import 'package:aq_graph_engine/server.dart';  // ✅ Сервер
import 'package:aq_security/aq_security.dart'; // ✅ Клиент
import 'package:dart_vault/dart_vault.dart';   // ✅ Клиент
import 'package:aq_tool_service/aq_tool_service.dart'; // ✅ Клиент

void main() async {
  // 1. Инициализация всех клиентов
  await AQSecurity.connect('http://auth-service:8080');
  await Vault.connect('http://vault-service:8765');
  await ToolService.connect('http://tools-service:9090');

  // 2. Создание сервера движка
  final engine = GraphEngine(
    auth: AQSecurity.instance,
    vault: Vault.instance,
    tools: ToolService.instance,
  );

  // 3. Регистрация
  AQPlatform.init(
    auth: AQSecurity.instance,
    vault: Vault.instance,
    tools: ToolService.instance,
    engine: engine,
  );

  // 4. Запуск
  await engine.serve(port: 9000);
  print('Graph engine running on :9000');
}

step.code:
// aq_schema/security.dart
abstract interface class IAQAuthService {
  static IAQAuthService get instance => AQPlatform.resolve();

  Future<bool> canAccess(String userId, String resource, String action);
}

// aq_security/lib/server/auth_service.dart
class AuthService implements IAQAuthService {
  @override
  Future<bool> canAccess(String userId, String resource, String action) {
    // Вся логика проверки прав
    final user = await _loadUser(userId);
    final policy = await _getPolicy(resource);
    return policy.allows(user, action);
  }
}

// dart_vault/lib/server/vault_storage.dart
import 'package:aq_schema/security.dart'; // ✅ Только интерфейс!

class VaultStorage {
  Future<void> write(String key, value, String userId) async {
    // Делегирует проверку через порт
    final allowed = await IAQAuthService.instance
      .canAccess(userId, key, 'write');

    if (!allowed) throw AccessDenied();

    // Своя работа — хранение
    await _db.insert(key, value);
  }
}

// vault_service/main.dart
import 'package:dart_vault/server.dart';
import 'package:aq_security/aq_security.dart'; // Клиент

void main() async {
  // Security как удалённый клиент
  await AQSecurity.connect('http://auth-service:8080');

  // Vault как сервер
  final vaultServer = VaultStorage(db: postgres);

  // Регистрация: теперь VaultStorage.write() будет вызывать
  // AuthService.canAccess() через IAQAuthService.instance
  AQPlatform.init(
    auth: AQSecurity.instance,
    vault: vaultServer,
  );

  await vaultServer.serve(port: 8765);
}

