example.code:
// dart_vault/lib/client/vault_client.dart
class VaultClient implements IAQVaultClient {
  final HttpClient _http;

  @override
  Future<void> write(String key, dynamic value) async {
    // Просто отправляет. Вся логика на сервере.
    final response = await _http.post('/vault/write', 
      body: {'key': key, 'value': value}
    );

    if (!response.ok) throw VaultException(response.error);
  }
}

// ❌ НЕПРАВИЛЬНО — толстый клиент
class VaultClient {
  Future<void> write(String key, dynamic value) async {
    // ❌ Валидация на клиенте
    if (key.isEmpty) throw ValidationError();

    // ❌ Проверка прав на клиенте
    if (!_localCache.canWrite(key)) throw AccessDenied();

    await _http.post('/vault/write', body: {...});
  }
}
